import{_ as i,c as r,o as n,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"v1.2.3: Database Stability Enhancement","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.3.md","filePath":"en/changelog/v1.2.3.md","lastUpdated":1772014034000}'),o={name:"en/changelog/v1.2.3.md"};function s(l,a,h,d,c,p){return n(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-3-database-stability-enhancement" tabindex="-1">v1.2.3: Database Stability Enhancement <a class="header-anchor" href="#v1-2-3-database-stability-enhancement" aria-label="Permalink to “v1.2.3: Database Stability Enhancement”">​</a></h1><p><strong>Release Date</strong>: February 15, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update improves <strong>database stability and reliability</strong>, and fixes some model variant identification issues.</p><hr><h2 id="new-feature-database-checkpoints" tabindex="-1">New Feature: Database Checkpoints <a class="header-anchor" href="#new-feature-database-checkpoints" aria-label="Permalink to “New Feature: Database Checkpoints”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added WAL (Write-Ahead Logging) checkpoint mechanism for the SQLite database.</p><h3 id="what-is-a-wal-checkpoint" tabindex="-1">What is a WAL checkpoint? <a class="header-anchor" href="#what-is-a-wal-checkpoint" aria-label="Permalink to “What is a WAL checkpoint?”">​</a></h3><p>Simply put, it <strong>periodically writes temporary data to the main file</strong> to prevent data loss.</p><p>Imagine you&#39;re writing an article:</p><ul><li><strong>Without checkpoint</strong>: All content is cached, computer suddenly shuts down → content lost</li><li><strong>With checkpoint</strong>: Auto-saves every paragraph → won&#39;t lose much content</li></ul><h3 id="what-are-the-benefits-for-users" tabindex="-1">What are the benefits for users? <a class="header-anchor" href="#what-are-the-benefits-for-users" aria-label="Permalink to “What are the benefits for users?”">​</a></h3><ul><li>More reliable data persistence</li><li>More reasonable database file size</li><li>Safer data when unexpectedly closed</li></ul><hr><h2 id="bug-fix-model-variant-identification" tabindex="-1">Bug Fix: Model Variant Identification <a class="header-anchor" href="#bug-fix-model-variant-identification" aria-label="Permalink to “Bug Fix: Model Variant Identification”">​</a></h2><h3 id="the-previous-problem" tabindex="-1">The Previous Problem <a class="header-anchor" href="#the-previous-problem" aria-label="Permalink to “The Previous Problem”">​</a></h3><p>When using providers like OpenRouter, variants of certain Anthropic models might not be correctly identified.</p><h3 id="the-current-situation" tabindex="-1">The Current Situation <a class="header-anchor" href="#the-current-situation" aria-label="Permalink to “The Current Situation”">​</a></h3><p>Fixed this issue, ensuring Anthropic models on OpenRouter also support variant functionality.</p><p>Also fixed the variant passing issue for Vercel Bedrock models.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using OpenRouter</td><td>✅ Upgrade</td></tr><tr><td>Using Vercel Bedrock</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next release</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',26),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-optional" tabindex="-1">Technical Details (Optional) <a class="header-anchor" href="#technical-details-optional" aria-label="Permalink to “Technical Details (Optional)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure Anthropic models on OpenRouter also support variants</li><li>Added WAL checkpoint when database opens</li><li>Ensure Vercel variants pass Amazon models under Bedrock key</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const m=i(o,[["render",s]]);export{b as __pageData,m as default};
